  ('elementary-8b44517b-moex-00643', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依現行勞資爭議處理法之規定，下列關於工會罷工時應遵守規定之敘述，何者錯誤？', '["罷工應依誠實信用及權利不得濫用原則為之", "罷工時不得妨害公共秩序之安寧", "罷工期間，爭議當事人雙方應維持工作場所安全及衛生設備之正常運轉", "工會非經會員以直接、無記名投票且經全體過半數同意，不得宣告罷工及設置糾察線"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00644', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依現行勞資爭議處理法之規定，經法院核定之裁決有無效或得撤銷之原因者，當事人若欲向原核定法院 提起宣告裁決無效或撤銷裁決之訴，最遲應於法院核定之裁決決定書送達後幾日內提起？', '["10日", "20日", "30日", "60日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
