  ('elementary-8b44517b-moex-00646', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依性別工作平等法之規定，下列關於促進工作平等措施之敘述，何者錯誤？', '["產檢假及陪產假期間，薪資照給", "女性受僱者因生理日致工作有困難者，每月得請生理假一日，薪資照給", "子女未滿二歲須受僱者親自哺（集）乳者，除規定之休息時間外，雇主應每日另給哺（集）乳時間六 十分鐘，薪資照給", "受僱於僱用三十人以上雇主之受僱者，為撫育未滿三歲子女，得向雇主請求每天減少工作時間一小時； 減少之工作時間，不得請求報酬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
